mapper.select:
/* TC_ECS_DOC_CLS_CD_Dao_retrieveDocClCd */ SELECT LEVEL AS lv, A.DOC_CLS_CD, A.DOC_CLS_NM, A.UPPER_DOC_CLS_CD, A.SYS_DIV_CD, A.FILE_MAIN_PATH, A.MENU_ID FROM TC_ECS_DOC_CLS_CD A WHERE 1 = 1
AND A.SYS_DIV_CD = #{sysDivCd}
START WITH A.UPPER_DOC_CLS_CD IS NULL
START WITH A.UPPER_DOC_CLS_CD = #{upperDocClsCd}
CONNECT BY A.UPPER_DOC_CLS_CD = PRIOR A.DOC_CLS_CD ORDER SIBLINGS BY A.DOC_CLS_CD

mapper.update:
/*TC_ECS_DOC_CLS_CD_Dao_updateDocClsCd*/
UPDATE
	TC_ECS_DOC_CLS_CD
SET
	DOC_CLS_NM = #{docClsNm},
	UPPER_DOC_CLS_CD = #{upperDocClsCd},
	LAST_UPDT_DT = SYSDATE,
	LAST_UPDUSR_ID = #{lastUpdusrId}
WHERE
	DOC_CLS_CD = #{docClsCd}
